(async () => {
  let tweetId = '${{ args.tweet-id }}';
  const urlMatch = tweetId.match(/\/status\/(\d+)/);
  if (urlMatch) tweetId = urlMatch[1];

  const limit = parseInt('${{ args.limit }}');
  const ct0 = document.cookie.split(';').map(c=>c.trim()).find(c=>c.startsWith('ct0='))?.split('=')[1];
  if (!ct0) throw new Error('Not logged into x.com');

  const bearer = 'AAAAAAAAAAAAAAAAAAAAANRILgAAAAAAnNwIzUejRCOuH5E6I8xnZz4puTs%3D1Zv7ttfk8LF81IUq16cHjhLTvJu4FA33AGWWjCpTnA';
  const queryId = 'nBS-WpgA6ZG0CyNHD517JQ';
  const headers = {
    'Authorization': 'Bearer ' + decodeURIComponent(bearer),
    'X-Csrf-Token': ct0,
    'X-Twitter-Auth-Type': 'OAuth2Session',
    'X-Twitter-Active-User': 'yes'
  };

  const variables = { focalTweetId: tweetId, referrer: 'tweet', includePromotedContent: false };
  const features = { longform_notetweets_consumption_enabled: true };
  const apiUrl = `/i/api/graphql/${queryId}/TweetDetail?variables=${encodeURIComponent(JSON.stringify(variables))}&features=${encodeURIComponent(JSON.stringify(features))}`;

  const resp = await fetch(apiUrl, { headers, credentials: 'include' });
  if (!resp.ok) throw new Error('HTTP ' + resp.status);
  const data = await resp.json();

  const instructions = data?.data?.threaded_conversation_with_injections_v2?.instructions || [];
  const results = [];
  const seen = new Set();

  for (const inst of instructions) {
    for (const entry of inst.entries || []) {
      const tw = entry.content?.itemContent?.tweet_results?.result;
      if (tw && tw.rest_id && !seen.has(tw.rest_id)) {
        seen.add(tw.rest_id);
        const legacy = tw.legacy || {};
        const user = tw.core?.user_results?.result;
        const screenName = user?.legacy?.screen_name || user?.core?.screen_name || 'unknown';
        const noteText = tw.note_tweet?.note_tweet_results?.result?.text;

        results.push({
          id: tw.rest_id,
          author: screenName,
          text: noteText || legacy.full_text || '',
          likes: legacy.favorite_count || 0,
          url: `https://x.com/${screenName}/status/${tw.rest_id}`
        });
      }

      for (const item of entry.content?.items || []) {
        const nested = item.item?.itemContent?.tweet_results?.result;
        if (nested && nested.rest_id && !seen.has(nested.rest_id)) {
          seen.add(nested.rest_id);
          const legacy = nested.legacy || {};
          const user = nested.core?.user_results?.result;
          const screenName = user?.legacy?.screen_name || user?.core?.screen_name || 'unknown';
          const noteText = nested.note_tweet?.note_tweet_results?.result?.text;

          results.push({
            id: nested.rest_id,
            author: screenName,
            text: noteText || legacy.full_text || '',
            likes: legacy.favorite_count || 0,
            url: `https://x.com/${screenName}/status/${nested.rest_id}`
          });
        }
      }
    }
  }

  return results.slice(0, limit);
})()
